    "id": "quantitative-primer-problem-034",
    "titleEn": "Question 34 - 5-06 2000-05-12 Write a query to return all the customers who have made changes to their details",
    "titleZh": "Question 34 - 5-06 2000-05-12 Write a query to return all the customers who have made changes to their details",
    "category": "pandasNumpy",
