    "id": "quantitative-primer-problem-041",
    "titleEn": "Question 41 - You have a bag with 1000 coins in it",
    "titleZh": "Question 41 - You have a bag with 1000 coins in it",
    "category": "machineLearning",
    "difficulty": "Hard",
    "tags": [
      "Quantitative Primer",
      "Machine Learning",
      "Question 41",
      "probability"
    ],
    "source": "quantitative-primer",
    "sourceUrl": "Quantitative Primer",
    "sourceType": "book",
